import{_ as a,o as t,c as s,a2 as i}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 6 — Your First Launch","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/06-your-first-launch.md","filePath":"chapters/06-your-first-launch.md"}'),n={name:"chapters/06-your-first-launch.md"};function o(l,e,p,d,r,h){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="chapter-6-—-your-first-launch" tabindex="-1">Chapter 6 — Your First Launch <a class="header-anchor" href="#chapter-6-—-your-first-launch" aria-label="Permalink to &quot;Chapter 6 — Your First Launch&quot;">​</a></h1><blockquote><p><em>&quot;The moment you open Vim for the first time, you enter a new world of editing.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐ Beginner <strong>Estimated Reading Time:</strong> 15–20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>You&#39;ve installed Vim or Neovim.</p><p>Now what?</p><p>This chapter walks through your very first session step by step.</p><p>By the end, you&#39;ll be able to:</p><ul><li>Open and close Vim</li><li>Understand the screen layout</li><li>Navigate the help system</li><li>Create, edit, and save a file</li></ul><hr><h1 id="opening-vim" tabindex="-1">Opening Vim <a class="header-anchor" href="#opening-vim" aria-label="Permalink to &quot;Opening Vim&quot;">​</a></h1><p>Open your terminal and type:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span></span></code></pre></div><p>or</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nvim</span></span></code></pre></div><p>You should see:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~                              </span></span>
<span class="line"><span>~                              </span></span>
<span class="line"><span>~                              </span></span>
<span class="line"><span>~                              </span></span>
<span class="line"><span>~                              </span></span>
<span class="line"><span>   VIM - Vi IMproved           </span></span>
<span class="line"><span>                              </span></span>
<span class="line"><span>   version 9.0                </span></span>
<span class="line"><span>   by Bram Moolenaar et al.   </span></span>
<span class="line"><span>   Vim is open source and freely distributable</span></span>
<span class="line"><span>   +---------------------------+</span></span>
<span class="line"><span>   | Donate to help children   |</span></span>
<span class="line"><span>   | in Uganda!                |</span></span>
<span class="line"><span>   +---------------------------+</span></span></code></pre></div><p>With Neovim, you might see a slightly different startup screen.</p><hr><h1 id="understanding-the-screen" tabindex="-1">Understanding the Screen <a class="header-anchor" href="#understanding-the-screen" aria-label="Permalink to &quot;Understanding the Screen&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+------------------------------------------+</span></span>
<span class="line"><span>| &quot; practice.txt         4,1           All |</span></span>
<span class="line"><span>|------------------------------------------|</span></span>
<span class="line"><span>| Line 1: This is my practice file.        |</span></span>
<span class="line"><span>| Line 2: I am learning Vim.              |</span></span>
<span class="line"><span>| Line 3:                               |</span></span>
<span class="line"><span>| Line 4:                               |</span></span>
<span class="line"><span>| ...                                    |</span></span>
<span class="line"><span>| ~                                       |</span></span>
<span class="line"><span>| ~                                       |</span></span>
<span class="line"><span>| ~                                       |</span></span>
<span class="line"><span>|------------------------------------------|</span></span>
<span class="line"><span>| :                                      |</span></span>
<span class="line"><span>+------------------------------------------+</span></span></code></pre></div><h2 id="the-main-area" tabindex="-1">The Main Area <a class="header-anchor" href="#the-main-area" aria-label="Permalink to &quot;The Main Area&quot;">​</a></h2><p>This is where your file content appears.</p><p>Empty lines show a <code>~</code> character (tilde).</p><h2 id="the-status-line" tabindex="-1">The Status Line <a class="header-anchor" href="#the-status-line" aria-label="Permalink to &quot;The Status Line&quot;">​</a></h2><p>The bottom line shows:</p><ul><li>File name</li><li>Line number</li><li>Column number</li><li>File status</li></ul><h2 id="the-command-line" tabindex="-1">The Command Line <a class="header-anchor" href="#the-command-line" aria-label="Permalink to &quot;The Command Line&quot;">​</a></h2><p>The very last line is where commands appear.</p><hr><h1 id="how-to-quit-vim" tabindex="-1">How to Quit Vim <a class="header-anchor" href="#how-to-quit-vim" aria-label="Permalink to &quot;How to Quit Vim&quot;">​</a></h1><p>This is the most famous Vim meme:</p><blockquote><p>&quot;How do I exit Vim?&quot;</p></blockquote><p>Here&#39;s how:</p><p>Press <strong>Escape</strong> to make sure you&#39;re in normal mode.</p><p>Then type:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:q!</span></span></code></pre></div><p>Then press <strong>Enter</strong>.</p><p>This quits Vim without saving changes.</p><h2 id="other-ways-to-quit" tabindex="-1">Other Ways to Quit <a class="header-anchor" href="#other-ways-to-quit" aria-label="Permalink to &quot;Other Ways to Quit&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:q</code></td><td>Quit (only if no unsaved changes)</td></tr><tr><td><code>:q!</code></td><td>Quit and discard unsaved changes</td></tr><tr><td><code>:wq</code></td><td>Save and quit</td></tr><tr><td><code>:x</code></td><td>Save and quit (same as <code>:wq</code>)</td></tr><tr><td><code>:w</code></td><td>Save only (don&#39;t quit)</td></tr><tr><td><code>ZZ</code></td><td>Save and quit (no colon needed)</td></tr><tr><td><code>ZQ</code></td><td>Quit without saving (no colon needed)</td></tr></tbody></table><hr><h1 id="opening-a-file" tabindex="-1">Opening a File <a class="header-anchor" href="#opening-a-file" aria-label="Permalink to &quot;Opening a File&quot;">​</a></h1><p>To open an existing file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> filename.txt</span></span></code></pre></div><p>To create a new file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> newfile.txt</span></span></code></pre></div><p>If <code>newfile.txt</code> doesn&#39;t exist, Vim creates an empty buffer. When you save, the file is created on disk.</p><h2 id="open-multiple-files" tabindex="-1">Open Multiple Files <a class="header-anchor" href="#open-multiple-files" aria-label="Permalink to &quot;Open Multiple Files&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file1.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file2.txt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file3.txt</span></span></code></pre></div><p>Use <code>:next</code> and <code>:prev</code> to switch between them.</p><hr><h1 id="your-first-edit" tabindex="-1">Your First Edit <a class="header-anchor" href="#your-first-edit" aria-label="Permalink to &quot;Your First Edit&quot;">​</a></h1><p>Let&#39;s create and edit a file step by step.</p><h2 id="step-1-open-vim" tabindex="-1">Step 1: Open Vim <a class="header-anchor" href="#step-1-open-vim" aria-label="Permalink to &quot;Step 1: Open Vim&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello.txt</span></span></code></pre></div><h2 id="step-2-enter-insert-mode" tabindex="-1">Step 2: Enter Insert Mode <a class="header-anchor" href="#step-2-enter-insert-mode" aria-label="Permalink to &quot;Step 2: Enter Insert Mode&quot;">​</a></h2><p>Press the letter <code>i</code>.</p><p>Look at the bottom left:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-- INSERT --</span></span></code></pre></div><p>This means you&#39;re in insert mode. Now keys type text.</p><h2 id="step-3-type-something" tabindex="-1">Step 3: Type Something <a class="header-anchor" href="#step-3-type-something" aria-label="Permalink to &quot;Step 3: Type Something&quot;">​</a></h2><p>Type:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello, Vim!</span></span>
<span class="line"><span>I am learning to edit text.</span></span></code></pre></div><h2 id="step-4-return-to-normal-mode" tabindex="-1">Step 4: Return to Normal Mode <a class="header-anchor" href="#step-4-return-to-normal-mode" aria-label="Permalink to &quot;Step 4: Return to Normal Mode&quot;">​</a></h2><p>Press <strong>Escape</strong>.</p><p>The <code>-- INSERT --</code> indicator disappears.</p><h2 id="step-5-save-the-file" tabindex="-1">Step 5: Save the File <a class="header-anchor" href="#step-5-save-the-file" aria-label="Permalink to &quot;Step 5: Save the File&quot;">​</a></h2><p>Type <code>:w</code> and press <strong>Enter</strong>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:w</span></span></code></pre></div><p>You should see:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;hello.txt&quot; 2L, 40B written</span></span></code></pre></div><h2 id="step-6-quit-vim" tabindex="-1">Step 6: Quit Vim <a class="header-anchor" href="#step-6-quit-vim" aria-label="Permalink to &quot;Step 6: Quit Vim&quot;">​</a></h2><p>Type <code>:q</code> and press <strong>Enter</strong>.</p><p>Congratulations. You just created your first file with Vim.</p><hr><h1 id="navigation-basics" tabindex="-1">Navigation Basics <a class="header-anchor" href="#navigation-basics" aria-label="Permalink to &quot;Navigation Basics&quot;">​</a></h1><p>Now reopen <code>hello.txt</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vim</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> hello.txt</span></span></code></pre></div><p>In normal mode, you can move the cursor with:</p><table tabindex="0"><thead><tr><th>Key</th><th>Direction</th></tr></thead><tbody><tr><td><code>h</code></td><td>Left</td></tr><tr><td><code>j</code></td><td>Down</td></tr><tr><td><code>k</code></td><td>Up</td></tr><tr><td><code>l</code></td><td>Right</td></tr></tbody></table><p>Arrow keys also work, but training yourself to use <code>h</code>/<code>j</code>/<code>k</code>/<code>l</code> will be faster in the long run.</p><h2 id="try-these" tabindex="-1">Try These <a class="header-anchor" href="#try-these" aria-label="Permalink to &quot;Try These&quot;">​</a></h2><ul><li>Press <code>j</code> to move down.</li><li>Press <code>k</code> to move up.</li><li>Press <code>l</code> to move right.</li><li>Press <code>h</code> to move left.</li></ul><hr><h1 id="the-help-system" tabindex="-1">The Help System <a class="header-anchor" href="#the-help-system" aria-label="Permalink to &quot;The Help System&quot;">​</a></h1><p>Vim has an extensive built-in help system.</p><p>Open help with:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:help</span></span></code></pre></div><p>This opens a help window.</p><p>Navigate help like any Vim file.</p><p>Search for specific topics:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:help navigation</span></span>
<span class="line"><span>:help insert</span></span>
<span class="line"><span>:help saving</span></span></code></pre></div><p>Close the help window with:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:q</span></span></code></pre></div><h2 id="help-tips" tabindex="-1">Help Tips <a class="header-anchor" href="#help-tips" aria-label="Permalink to &quot;Help Tips&quot;">​</a></h2><ul><li>Help files use <code>.txt</code> extension.</li><li>Tags appear between <code>|</code> bars—you can jump to them with <code>Ctrl+]</code>.</li><li>Go back with <code>Ctrl+O</code>.</li><li><code>:help :w</code> explains the <code>:w</code> command.</li><li><code>:help i</code> explains insert mode.</li></ul><hr><h1 id="practice-your-first-session" tabindex="-1">Practice: Your First Session <a class="header-anchor" href="#practice-your-first-session" aria-label="Permalink to &quot;Practice: Your First Session&quot;">​</a></h1><p>Open Vim and try this:</p><ol><li>Open a file called <code>practice.md</code>.</li><li>Enter insert mode by pressing <code>i</code>.</li><li>Write a short paragraph about why you want to learn Vim.</li><li>Press <strong>Escape</strong> to return to normal mode.</li><li>Save with <code>:w</code>.</li><li>Move around the file using <code>h</code>, <code>j</code>, <code>k</code>, <code>l</code>.</li><li>Quit with <code>:q</code>.</li></ol><hr><h1 id="common-beginner-mistakes" tabindex="-1">Common Beginner Mistakes <a class="header-anchor" href="#common-beginner-mistakes" aria-label="Permalink to &quot;Common Beginner Mistakes&quot;">​</a></h1><h2 id="typing-in-normal-mode" tabindex="-1">Typing in Normal Mode <a class="header-anchor" href="#typing-in-normal-mode" aria-label="Permalink to &quot;Typing in Normal Mode&quot;">​</a></h2><p>If you&#39;re in normal mode and type <code>d</code>, <code>i</code>, <code>e</code>, etc., Vim interprets them as commands, not text.</p><p>If unexpected things happen, press <strong>Escape</strong> to return to normal mode.</p><h2 id="can-t-exit-insert-mode" tabindex="-1">Can&#39;t Exit Insert Mode <a class="header-anchor" href="#can-t-exit-insert-mode" aria-label="Permalink to &quot;Can&#39;t Exit Insert Mode&quot;">​</a></h2><p>Press <strong>Escape</strong>. If that doesn&#39;t work, try <code>Ctrl+C</code> or <code>Ctrl+[</code> (which is equivalent to Escape).</p><h2 id="accidentally-opened-help" tabindex="-1">Accidentally Opened Help <a class="header-anchor" href="#accidentally-opened-help" aria-label="Permalink to &quot;Accidentally Opened Help&quot;">​</a></h2><p>Type <code>:q</code> to close the help window.</p><h2 id="lost-in-commands" tabindex="-1">Lost in Commands <a class="header-anchor" href="#lost-in-commands" aria-label="Permalink to &quot;Lost in Commands&quot;">​</a></h2><p>Press <strong>Escape</strong> a few times to reset to normal mode.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li>Opening Vim: <code>vim filename</code></li><li>Entering insert mode: <code>i</code></li><li>Returning to normal mode: <strong>Escape</strong></li><li>Saving: <code>:w</code></li><li>Quitting: <code>:q</code> or <code>:q!</code></li><li>Navigating: <code>h</code>, <code>j</code>, <code>k</code>, <code>l</code></li><li>Help: <code>:help</code></li></ul><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li>Vim has two main modes you&#39;ll use constantly: <strong>normal</strong> and <strong>insert</strong>.</li><li>Insert mode types text; normal mode runs commands.</li><li>Knowing how to exit Vim is your first milestone.</li><li>The built-in help system is comprehensive and always available.</li><li>Practice the <code>h</code>, <code>j</code>, <code>k</code>, <code>l</code> keys—they form the foundation of Vim navigation.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open Vim and enter insert mode by pressing <code>i</code>. Type your name.</li><li>Return to normal mode with Escape. Save and quit with <code>:wq</code>.</li><li>Reopen the file and navigate using <code>h</code>, <code>j</code>, <code>k</code>, <code>l</code>.</li><li>Open the help system with <code>:help</code> and explore a topic.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><strong><a href="./07-understanding-modes.html">Chapter 7 — Understanding Modes</a></strong></p><p>The most important concept in Vim. We&#39;ll explore all four modes, when to use each, and how to switch between them efficiently.</p>`,127)])])}const m=a(n,[["render",o]]);export{u as __pageData,m as default};
